const { BigQuery } = require('@google-cloud/bigquery');

exports.processBigData = async (req, res) => {
  const bigquery = new BigQuery();

  const projectId = process.env.BIGQUERY_PROJECT_ID || 'your-gcp-project-id'; // Replace with your GCP project ID or set via env var
  const datasetId = process.env.BIGQUERY_DATASET_ID || 'your_dataset_id'; // Replace with your BigQuery dataset ID or set via env var
  const tableId = process.env.BIGQUERY_TABLE_ID || 'your_table_id'; // Replace with your BigQuery table ID or set via env var

  // Define the BigQuery SQL query for aggregation.
  // This example counts all records and sums a hypothetical 'value_column'
  // for data from the last 24 hours. Adjust the query to your specific needs.
  const query = `
    SELECT
      COUNT(*) AS total_records,
      SUM(your_numeric_column) AS total_aggregated_value,
      AVG(your_numeric_column) AS average_aggregated_value
    FROM
      \`${projectId}.${datasetId}.${tableId}\`
    WHERE
      your_timestamp_column >= TIMESTAMP_SUB(CURRENT_TIMESTAMP(), INTERVAL 1 DAY)
    -- Add more WHERE clauses, GROUP BY, HAVING, ORDER BY as needed for your aggregation
  `;

  const options = {
    query: query,
    // Specify the BigQuery dataset location. Must match the location of your dataset.
    location: 'US', // e.g., 'US', 'europe-west1', 'asia-south1'
    useLegacySql: false, // Use standard SQL
  };

  try {
    // Run the query as a BigQuery job. This is asynchronous and handles large queries efficiently.
    const [job] = await bigquery.createQueryJob(options);

    // Wait for the query to complete and get the results.
    const [rows] = await job.getQueryResults();

    res.status(200).json({
      message: 'BigQuery aggregation completed successfully.',
      results: rows,
      jobId: job.id,
    });

  } catch (error) {
    console.error('Error during BigQuery aggregation:', error);
    res.status(500).json({
      message: 'Failed to perform BigQuery aggregation.',
      error: error.message,
    });
  }
};